import React, { useMemo } from "react";
import { type UserAssetDatum } from "@avail-project/nexus-core";
import Decimal from "decimal.js";
import {
  formatTokenAmountDisplay,
  formatUsdBalanceLabel,
} from "./swap-asset-selector";

interface AmountInputUnifiedProps {
  amount: string;
  onChange: (value: string) => void;
  onCommit?: (value: string) => void;
  disabled?: boolean;
  maxAvailableAmount?: string;
  unifiedBalances?: UserAssetDatum[];
  tokenIcon?: React.ReactNode;
  usdValue?: string;
  /** Label shown beside Balance text, e.g. "USDC" */
  tokenSymbol?: string;
  header?: React.ReactNode;
}

export function AmountInputUnified({
  amount,
  onChange,
  onCommit,
  disabled,
  maxAvailableAmount,
  unifiedBalances,
  tokenIcon,
  usdValue,
  tokenSymbol,
  header,
}: AmountInputUnifiedProps) {
  const handleMax = () => {
    if (!totalBalanceValue) return;
    onChange(totalBalanceValue);
    onCommit?.(totalBalanceValue);
  };

  const isUsdMode = !tokenSymbol;
  const totalBalanceValue = useMemo(() => {
    if (!unifiedBalances || !unifiedBalances.length) return "";
    if (isUsdMode) {
      return unifiedBalances
        .reduce(
          (acc, curr) => acc.add(curr.balanceInFiat ?? 0),
          new Decimal(0),
        )
        .toDecimalPlaces(8, Decimal.ROUND_DOWN)
        .toFixed();
    }
    return unifiedBalances
      .reduce((acc, curr) => acc.add(curr.balance ?? 0), new Decimal(0))
      .toDecimalPlaces(8, Decimal.ROUND_DOWN)
      .toFixed();
  }, [isUsdMode, unifiedBalances]);
  const totalBalanceLabel = useMemo(() => {
    if (!unifiedBalances || !unifiedBalances.length) return "0";
    if (isUsdMode) {
      const fiatAmount = unifiedBalances.reduce(
        (acc, curr) => acc.add(curr.balanceInFiat ?? 0),
        new Decimal(0),
      );
      return formatUsdBalanceLabel(fiatAmount);
    }
    const amount = unifiedBalances.reduce(
      (acc, curr) => acc.add(curr.balance ?? 0),
      new Decimal(0),
    );
    return formatTokenAmountDisplay(amount);
  }, [isUsdMode, unifiedBalances]);

  return (
    <div
      className="w-full flex flex-col bg-white min-h-[168px]"
      style={{
        borderRadius: "12px",
        border: "1px solid var(--border-default, #E8E8E7)",
        boxShadow: "0px 1px 12px 0px #5B5B5B0D",
        background: "#FFFFFF",
      }}
    >
      {header && (
        <div className="w-full border-b border-[#E8E8E7] px-4 py-3">
          {header}
        </div>
      )}
      <div className="flex-1 w-full flex flex-col items-center justify-center p-4 relative">
      {/* Central Input row: large amount + MAX button inline */}
      <div className="flex items-center justify-center w-full gap-x-2 mb-1.5">
        <div
          className="flex items-center justify-center text-center"
          style={{
            fontSize: "34px",
            fontWeight: 500,
            gap: "2px",
          }}
        >
          {tokenIcon ? (
            <div className="flex items-center justify-center mr-3">
              {tokenIcon}
            </div>
          ) : (
            <span className="leading-none text-gray-800 mr-1.5">$</span>
          )}
          <input
            type="text"
            inputMode="decimal"
            placeholder="0"
            className="min-w-0 text-start bg-transparent border-none outline-none p-0 focus:ring-0 placeholder:text-gray-300 truncate tabular-nums"
            style={{
              fontFamily: "'Delight', sans-serif",
              fontWeight: 500,
              fontSize: "34px",
              lineHeight: "100%",
              height: "34px",
              letterSpacing: "2%",
              color: "var(--foreground-primary, #161615)",
              fieldSizing: "content",
              minWidth: "1ch",
              maxWidth: "6ch",
            }}
            value={amount}
            disabled={disabled}
            onChange={(e) => {
              let next = e.target.value.replaceAll(/[^0-9.]/g, "");
              const parts = next.split(".");
              if (parts.length > 2)
                next = parts[0] + "." + parts.slice(1).join("");
              if (next === ".") next = "0.";
              onChange(next);
            }}
            onBlur={() => onCommit?.(amount)}
            onKeyDown={(e) => {
              if (e.key === "Enter") onCommit?.(amount);
            }}
          />
        </div>
        {/* MAX button — inline beside the input */}
        <button
          onClick={handleMax}
          disabled={disabled || !maxAvailableAmount}
          className="shrink-0 focus:opacity-80 disabled:opacity-40 disabled:cursor-not-allowed transition-opacity"
          style={{
            background: "var(--background-tertiary, #F0F0EF)",
            width: "40px",
            height: "22px",
            borderRadius: "6px",
            padding: "3px 7px",
            color: "var(--foreground-muted, #848483)",
            fontFamily:
              "var(--font-geist-mono), ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace",
            fontWeight: 400,
            fontSize: "10px",
            lineHeight: "100%",
          }}
        >
          MAX
        </button>
      </div>

      {/* Balance display — below amount + MAX row */}
      {(totalBalanceValue || maxAvailableAmount) && (
        <div className="absolute bottom-4 left-0 w-full flex justify-center">
          <p
            style={{
              color: "var(--widget-card-foreground-muted, #848483)",
              fontFamily:
                "var(--font-geist-sans), ui-sans-serif, system-ui, sans-serif",
              fontWeight: 400,
              fontSize: "12px",
              lineHeight: "100%",
              textAlign: "center",
            }}
          >
            Balance: {totalBalanceLabel || "0"}{tokenSymbol ? ` ${tokenSymbol}` : ""}
          </p>
        </div>
      )}
      </div>
    </div>
  );
}

import React, { useRef, useState } from "react";
import Decimal from "decimal.js";
import { AlertCircle, ChevronDown, Loader2 } from "lucide-react";
import { PayWithSources as SharedPayWithSources } from "./pay-with-sources";
import {
  formatSelectedTokenBalanceLabel,
  formatUsdBalanceLabel,
  type SwapTokenOption,
} from "./swap-asset-selector";

interface DepositIdleFormProps {
  amount: string;
  amountMode: "token" | "usd";
  onAmountChange: (val: string) => void;
  onAmountModeToggle: () => void;
  toToken?: SwapTokenOption;
  totalBalance: string;
  usdValue: string;
  tokenValue: string;
  fromTokens: SwapTokenOption[];
  onOpenSourcePicker: () => void;
  onSetPercent: (pct: number) => void;
  routeStatus?: "loading" | "insufficient";
  routeMessage?: string;
  isCalculatingMax?: boolean;
  calculatingPercent?: number | null;
  isQuoteRefreshing?: boolean;
  showAutoBadge?: boolean;
}

const uiFont = '"Geist", system-ui, sans-serif';
const primary = "#161615";
const muted = "#848483";
const border = "#E8E8E7";
const brand = "#006BF4";

const parseDecimal = (value: unknown) => {
  if (value === null || value === undefined || value === "") return undefined;
  if (Decimal.isDecimal(value)) return value;
  const cleaned = String(value).replace(/[^0-9.-]/g, "");
  if (!cleaned || cleaned === "-" || cleaned === "." || cleaned === "-.") {
    return undefined;
  }
  try {
    const parsed = new Decimal(cleaned);
    return parsed.isFinite() ? parsed : undefined;
  } catch {
    return undefined;
  }
};

const formatToken = (value: unknown) => {
  const amount = parseDecimal(value) ?? new Decimal(0);
  const max = amount.abs().gte(1) ? 6 : 8;
  return amount.toDecimalPlaces(max).toFixed();
};

const formatUsd = (value: unknown) => {
  const amount = parseDecimal(value) ?? new Decimal(0);
  if (amount.gt(0) && amount.lt(0.01)) return "<$0.01";
  return `$${amount.toDecimalPlaces(2).toFixed()}`;
};

const MAX_AMOUNT_DISPLAY_DECIMALS = 8;
const getTokenInputDecimals = (token?: Pick<SwapTokenOption, "decimals">) => {
  const decimals = Number(token?.decimals);
  return Number.isFinite(decimals) && decimals >= 0 ? Math.floor(decimals) : 18;
};

const formatAmountInputDisplay = (value: string) => {
  if (!value) return "";
  try {
    return new Decimal(value)
      .toDecimalPlaces(MAX_AMOUNT_DISPLAY_DECIMALS, Decimal.ROUND_DOWN)
      .toFixed();
  } catch {
    return value;
  }
};

const sanitizeAmountInput = (raw: string, maxDecimals: number) => {
  let next = raw.replaceAll(/[^0-9.]/g, "");
  const parts = next.split(".");
  if (parts.length > 2) next = parts[0] + "." + parts.slice(1).join("");
  const [integerPart, decimalPart] = next.split(".");
  if (decimalPart !== undefined) {
    next = `${integerPart}.${decimalPart.slice(0, Math.max(0, maxDecimals))}`;
  }
  if (next === ".") next = "0.";
  return next;
};

function TokenLogo({
  src,
  label,
  size = 30,
  fontSize = 12,
  style,
}: {
  src?: string;
  label?: string;
  size?: number;
  fontSize?: number;
  style?: React.CSSProperties;
}) {
  const [failed, setFailed] = useState(!src);

  React.useEffect(() => {
    setFailed(!src);
  }, [src]);

  if (!failed && src) {
    return (
      <img
        alt={label || ""}
        onError={() => setFailed(true)}
        src={src}
        style={{
          backgroundColor: "#FFFFFE",
          borderRadius: "999px",
          height: size,
          objectFit: "cover",
          width: size,
          ...style,
        }}
      />
    );
  }

  return (
    <div
      style={{
        alignItems: "center",
        backgroundColor: "#E8F0FF",
        borderRadius: "999px",
        color: brand,
        display: "flex",
        fontFamily: uiFont,
        fontSize,
        fontWeight: 700,
        height: size,
        justifyContent: "center",
        width: size,
        ...style,
      }}
    >
      {(label || "?").slice(0, 1).toUpperCase()}
    </div>
  );
}

function SourceLogoPair({ token }: { token: SwapTokenOption }) {
  return (
    <div style={{ flexShrink: 0, height: 32, position: "relative", width: 32 }}>
      <TokenLogo label={token.symbol} size={32} src={token.logo} />
      {token.chainLogo && (
        <TokenLogo
          label={token.chainName}
          size={14}
          src={token.chainLogo}
          style={{
            bottom: -2,
            outline: "1px solid #FFFFFE",
            position: "absolute",
            right: -2,
          }}
        />
      )}
    </div>
  );
}

function SkeletonRow() {
  return (
    <div style={{ alignItems: "center", display: "flex", justifyContent: "space-between" }}>
      <div
        style={{
          background:
            "linear-gradient(90deg, #F0F0EF 0%, #F7F7F6 48%, #F0F0EF 100%)",
          backgroundSize: "200% 100%",
          borderRadius: "6px",
          height: "32px",
          width: "128px",
        }}
        className="animate-pulse"
      />
      <div
        style={{
          background:
            "linear-gradient(90deg, #F0F0EF 0%, #F7F7F6 48%, #F0F0EF 100%)",
          backgroundSize: "200% 100%",
          borderRadius: "999px",
          height: "32px",
          width: "108px",
        }}
        className="animate-pulse"
      />
    </div>
  );
}

function PayWithSources({
  fromTokens,
  onOpenSourcePicker,
  routeStatus,
  routeMessage,
}: {
  fromTokens: SwapTokenOption[];
  onOpenSourcePicker: () => void;
  routeStatus?: "loading" | "insufficient";
  routeMessage?: string;
}) {
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const isRouteLoading = routeStatus === "loading";
  const shouldShowSourceSummary = !isRouteLoading && fromTokens.length > 0;
  const shouldScroll = shouldShowSourceSummary && fromTokens.length > 3;
  const autoBadge = (
    <span
      style={{
        border: `1px solid ${brand}`,
        borderRadius: "999px",
        color: brand,
        fontFamily: uiFont,
        fontSize: "9px",
        fontWeight: 600,
        letterSpacing: "0.04em",
        lineHeight: "12px",
        padding: "1px 5px",
      }}
    >
      AUTO
    </span>
  );

  return (
    <div
      style={{
        backgroundColor: "#FFFFFE",
        border: `1px solid ${border}`,
        borderRadius: "12px",
        boxShadow: "#1616150A 0px 1px 2px",
        boxSizing: "border-box",
        display: "flex",
        flexDirection: "column",
        gap: "10px",
        padding: "14px",
      }}
    >
      <div style={{ alignItems: "center", display: "flex", justifyContent: "space-between" }}>
        <div
          style={{
            alignItems: "center",
            color: muted,
            display: "flex",
            fontFamily: uiFont,
            fontSize: "12px",
            fontWeight: 500,
            gap: "6px",
            letterSpacing: "0.08em",
            lineHeight: "18px",
            textTransform: "uppercase",
          }}
        >
          <span>
            Pay With{shouldShowSourceSummary ? ` · ${fromTokens.length} assets` : ""}
          </span>
          {autoBadge}
        </div>
        {shouldShowSourceSummary && (
          <button
            onClick={onOpenSourcePicker}
            style={{
              backgroundColor: "#F4F7FE",
              border: "none",
              borderRadius: "6px",
              color: brand,
              cursor: "pointer",
              fontFamily: uiFont,
              fontSize: "12px",
              fontWeight: 500,
              lineHeight: "16px",
              padding: "7px 10px",
            }}
          >
            Edit tokens
          </button>
        )}
      </div>

      {isRouteLoading ? (
        <>
          <SkeletonRow />
          <div style={{ alignItems: "center", color: brand, display: "flex", fontFamily: uiFont, fontSize: "13px", gap: "6px" }}>
            <Loader2 className="animate-spin" style={{ height: 13, width: 13 }} />
            Calculating best route...
          </div>
        </>
      ) : shouldShowSourceSummary ? (
        <div style={{ position: "relative" }}>
          <div
            ref={scrollRef}
            style={{
              display: "flex",
              flexDirection: "column",
              maxHeight: shouldScroll ? "184px" : undefined,
              overflowY: shouldScroll ? "auto" : undefined,
              paddingRight: shouldScroll ? "6px" : 0,
            }}
          >
            {fromTokens.map((token, index) => (
              <div
                key={`${token.contractAddress}-${token.chainId ?? "unified"}-${index}`}
                style={{
                  alignItems: "center",
                  borderTop: index === 0 ? "none" : "1px solid #F0F0EF",
                  display: "flex",
                  justifyContent: "space-between",
                  minHeight: "52px",
                  padding: "6px 0",
                }}
              >
                <div style={{ alignItems: "center", display: "flex", gap: "10px", minWidth: 0 }}>
                  <SourceLogoPair token={token} />
                  <div style={{ display: "flex", flexDirection: "column", gap: "3px", minWidth: 0 }}>
                    <span style={{ color: primary, fontFamily: uiFont, fontSize: "14px", fontWeight: 600 }}>
                      {token.symbol}
                    </span>
                    <span
                      style={{
                        color: muted,
                        fontFamily: uiFont,
                        fontSize: "12px",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        whiteSpace: "nowrap",
                      }}
                    >
                      {token.isUnified ? "Unified balance" : `on ${token.chainName || "Unknown chain"}`}
                    </span>
                  </div>
                </div>
                <div style={{ display: "flex", flexDirection: "column", gap: "3px", textAlign: "right" }}>
                  <span style={{ color: primary, fontFamily: uiFont, fontSize: "13px" }}>
                    {formatToken(token.userAmount || token.balance)} {token.symbol}
                  </span>
                  <span style={{ color: muted, fontFamily: uiFont, fontSize: "12px" }}>
                    {formatUsd(token.userAmountUsd || token.balanceInFiat)}
                  </span>
                </div>
              </div>
            ))}
          </div>
          {shouldScroll && (
            <button
              aria-label="Scroll payment sources"
              onClick={() => scrollRef.current?.scrollBy({ behavior: "smooth", top: 64 })}
              style={{
                alignItems: "center",
                background: "#FFFFFE",
                border: `1px solid ${border}`,
                borderRadius: "999px",
                bottom: "4px",
                boxShadow: "0 2px 8px rgba(22,22,21,0.08)",
                cursor: "pointer",
                display: "flex",
                height: "22px",
                justifyContent: "center",
                left: "50%",
                padding: 0,
                position: "absolute",
                transform: "translateX(-50%)",
                width: "22px",
              }}
              type="button"
            >
              <ChevronDown style={{ color: muted, height: 14, width: 14 }} />
            </button>
          )}
        </div>
      ) : (
        <div
          style={{
            color: primary,
            fontFamily: uiFont,
            fontSize: "13px",
            lineHeight: "18px",
          }}
        >
          Sources will be auto selected
        </div>
      )}

      {routeStatus === "insufficient" && routeMessage && (
        <div
          style={{
            alignItems: "center",
            color: "#D32F2F",
            display: "flex",
            fontFamily: uiFont,
            fontSize: "13px",
            gap: "8px",
            lineHeight: "18px",
          }}
        >
          <AlertCircle style={{ flexShrink: 0, height: 15, width: 15 }} />
          {routeMessage}
        </div>
      )}
    </div>
  );
}

export function DepositIdleForm({
  amount,
  amountMode,
  onAmountChange,
  onAmountModeToggle,
  toToken,
  totalBalance,
  usdValue,
  tokenValue,
  fromTokens,
  onOpenSourcePicker,
  onSetPercent,
  routeStatus,
  routeMessage,
  isCalculatingMax,
  calculatingPercent,
  isQuoteRefreshing,
  showAutoBadge = true,
}: DepositIdleFormProps) {
  const [pendingPercent, setPendingPercent] = useState<number | null>(null);
  const [isAmountFocused, setIsAmountFocused] = useState(false);

  React.useEffect(() => {
    if (!isCalculatingMax) setPendingPercent(null);
  }, [isCalculatingMax]);

  const handlePercentSelect = (pct: number) => {
    setPendingPercent(pct);
    onSetPercent(pct);
  };

  const handleInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    onAmountChange(
      sanitizeAmountInput(
        e.target.value,
        isUsdMode ? MAX_AMOUNT_DISPLAY_DECIMALS : getTokenInputDecimals(toToken),
      ),
    );
  };
  const isUsdMode = amountMode === "usd";
  const amountDisplayValue = isAmountFocused
    ? amount
    : formatAmountInputDisplay(amount);
  const activePendingPercent =
    calculatingPercent ?? (isCalculatingMax ? pendingPercent : null);
  const isMaxCalculating = Boolean(isCalculatingMax && activePendingPercent === 100);
  const destinationBalanceLabel =
    isUsdMode
      ? formatUsdBalanceLabel(toToken?.balanceInFiat)
      : formatSelectedTokenBalanceLabel(toToken) || `0 ${toToken?.symbol || ""}`.trim();

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "12px", width: "100%" }}>
      <div
        style={{
          backgroundColor: "#FFFFFE",
          borderColor: border,
          borderRadius: "12px",
          borderStyle: "solid",
          borderWidth: "1px",
          boxShadow: "#1616150A 0px 1px 2px",
          boxSizing: "border-box",
          display: "flex",
          flexDirection: "column",
          gap: "10px",
          padding: "15px 14px",
        }}
      >
        <div style={{ alignItems: "center", display: "flex", justifyContent: "space-between" }}>
          <div style={{ color: muted, fontFamily: uiFont, fontSize: "12px", fontWeight: 500, letterSpacing: "0.08em", lineHeight: "20px", textTransform: "uppercase" }}>
            Deposit
          </div>
          <div style={{ alignItems: "center", display: "flex", gap: "4px" }}>
            <span style={{ color: muted, fontFamily: uiFont, fontSize: "13px", lineHeight: "18px" }}>
              Total Balance:
            </span>
            <span style={{ color: primary, fontFamily: uiFont, fontSize: "13px", fontWeight: 600, lineHeight: "18px" }}>
              ${totalBalance}
            </span>
          </div>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
          <div style={{ alignItems: "center", display: "flex", gap: "10px", justifyContent: "space-between", width: "100%" }}>
            <div style={{ alignItems: "baseline", display: "flex", flex: "1 1 0%", minWidth: 0 }}>
              {isMaxCalculating ? (
                <div
                  aria-label="Calculating max amount"
                  className="animate-pulse"
                  style={{
                    alignSelf: "center",
                    backgroundColor: "#F0F0EF",
                    borderRadius: "8px",
                    height: "34px",
                    maxWidth: "220px",
                    minWidth: "132px",
                    width: "62%",
                  }}
                />
              ) : (
                <>
                  {isUsdMode && amount && (
                    <span style={{ color: primary, fontFamily: '"Delight-Medium", "Delight", system-ui, sans-serif', fontSize: "30px", fontWeight: 500, lineHeight: "36px" }}>
                      $
                    </span>
                  )}
                  <input
                    type="text"
                    placeholder="0"
                    value={amountDisplayValue}
                    onChange={handleInput}
                    onFocus={() => setIsAmountFocused(true)}
                    onBlur={() => setIsAmountFocused(false)}
                    style={{
                      background: "transparent",
                      border: "none",
                      boxSizing: "border-box",
                      color: amount ? primary : "#9E9E9C",
                      fontFamily: '"Delight-Medium", "Delight", system-ui, sans-serif',
                      fontSize: "32px",
                      fontWeight: 500,
                      lineHeight: "38px",
                      minWidth: 0,
                      outline: "none",
                      padding: 0,
                      width: "100%",
                    }}
                  />
                </>
              )}
              {isCalculatingMax && !isMaxCalculating && (
                <Loader2
                  className="animate-spin"
                  style={{
                    alignSelf: "center",
                    color: brand,
                    flexShrink: 0,
                    height: 18,
                    marginLeft: 6,
                    width: 18,
                  }}
                />
              )}
            </div>

            <div
              style={{
                alignItems: "center",
                backgroundColor: "#FFFFFE",
                borderColor: border,
                borderRadius: "999px",
                borderStyle: "solid",
                borderWidth: "1px",
                boxShadow: "#1616150A 0px 1px 2px",
                boxSizing: "border-box",
                display: "inline-flex",
                flexShrink: 0,
                gap: "8px",
                height: "32px",
                paddingLeft: "4px",
                paddingRight: "10px",
              }}
            >
              <div style={{ flexShrink: 0, height: "24px", position: "relative", width: "24px" }}>
                <TokenLogo label={toToken?.symbol} size={24} src={toToken?.logo} />
                {toToken?.chainLogo && (
                  <TokenLogo
                    label={toToken.chainName}
                    size={12}
                    src={toToken.chainLogo}
                    style={{
                      bottom: -2,
                      outline: "1px solid #FFFFFE",
                      position: "absolute",
                      right: -2,
                    }}
                  />
                )}
              </div>
              <div style={{ color: primary, fontFamily: uiFont, fontSize: "15px", fontWeight: 600, lineHeight: "22px" }}>
                {toToken?.symbol || "Token"}
              </div>
            </div>
          </div>

          <div style={{ alignItems: "center", display: "flex", justifyContent: "space-between" }}>
            <button
              onClick={onAmountModeToggle}
              style={{
                background: "transparent",
                border: "none",
                color: muted,
                cursor: "pointer",
                fontFamily: uiFont,
                fontSize: "13px",
                lineHeight: "18px",
                padding: 0,
              }}
              type="button"
            >
              {isUsdMode
                ? `≈ ${tokenValue || "0"} ${toToken?.symbol || ""} ↕`
                : `≈ $${usdValue || "0"} ↕`}
            </button>
            <div style={{ alignItems: "center", display: "flex", gap: "5px" }}>
              <span style={{ color: "#7C7C7A", fontFamily: uiFont, fontSize: "13px", lineHeight: "18px" }}>
                Balance:
              </span>
              <span style={{ color: primary, fontFamily: uiFont, fontSize: "13px", fontWeight: 500, lineHeight: "18px" }}>
                {destinationBalanceLabel}
              </span>
            </div>
          </div>

          <div
            style={{
              alignItems: "center",
              display: "flex",
              gap: "5px",
              minHeight: "24px",
              width: "100%",
            }}
          >
            {[25, 50, 75].map((pct) => {
              const isPending = Boolean(isCalculatingMax && activePendingPercent === pct);
              return (
              <button
                key={pct}
                onMouseDown={(event) => event.preventDefault()}
                onClick={() => handlePercentSelect(pct)}
                style={{
                  alignItems: "center",
                  backgroundColor: isPending ? "#E8F0FF" : "#F4F4F3",
                  border: "none",
                  borderRadius: "7px",
                  cursor: "pointer",
                  display: "flex",
                  flex: "1 1 0%",
                  gap: "5px",
                  justifyContent: "center",
                  padding: "4px 7px",
                }}
                type="button"
              >
                {isPending && <Loader2 className="animate-spin" style={{ color: brand, height: 12, width: 12 }} />}
                <span style={{ color: isPending ? brand : "#363635", fontFamily: uiFont, fontSize: "11px", fontWeight: isPending ? 600 : 500, lineHeight: "16px" }}>
                  {pct}%
                </span>
              </button>
              );
            })}
            {(() => {
              const isPending = Boolean(isCalculatingMax && activePendingPercent === 100);
              return (
            <button
              onMouseDown={(event) => event.preventDefault()}
              onClick={() => handlePercentSelect(100)}
              style={{
                alignItems: "center",
                backgroundColor: isPending ? "#E8F0FF" : "#F4F4F3",
                border: "none",
                borderRadius: "7px",
                cursor: "pointer",
                display: "flex",
                flex: isPending ? "1.8 1 0%" : "1 1 0%",
                gap: "5px",
                justifyContent: "center",
                minWidth: 0,
                padding: "4px 7px",
              }}
              type="button"
            >
              {isPending && <Loader2 className="animate-spin" style={{ color: brand, height: 12, width: 12 }} />}
              <span style={{ color: isPending ? brand : "#363635", fontFamily: uiFont, fontSize: isPending ? "9px" : "11px", fontWeight: isPending ? 600 : 500, letterSpacing: "0.02em", lineHeight: "16px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                {isPending ? "Calculating Max..." : "MAX"}
              </span>
            </button>
              );
            })()}
          </div>
        </div>
      </div>

      <SharedPayWithSources
        fromTokens={fromTokens}
        onOpenSourcePicker={onOpenSourcePicker}
        routeMessage={routeMessage}
        routeStatus={routeStatus}
        showAutoBadge={showAutoBadge}
      />

    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import Decimal from "decimal.js";
import { Check, ChevronDown, Loader2, X } from "lucide-react";
import { type BridgeStepType, type SwapStepType } from "@avail-project/nexus-core";
import { type NexusOneMode, type DepositOpportunity } from "../types";
import { type SwapTokenOption } from "./swap-asset-selector";
import { type SwapIntentData } from "./swap-intent-preview";

type ProgressSdkStep = SwapStepType | BridgeStepType;

type ProgressStep = {
  id: number;
  completed: boolean;
  step: ProgressSdkStep;
};

export type NexusOneProgressEvent = {
  id: string;
  name: string;
  completed: boolean;
  step?: ProgressSdkStep;
  steps?: ProgressSdkStep[];
};

interface NexusOneProgressScreenProps {
  fromTokens?: SwapTokenOption[];
  toToken?: SwapTokenOption;
  fromAmountUsd?: string;
  toAmount?: string;
  toAmountUsd?: string;
  intentData?: SwapIntentData | null;
  mode: NexusOneMode;
  opportunity?: DepositOpportunity;
  steps?: ProgressStep[];
  progressEvents?: NexusOneProgressEvent[];
  failedStep?: ProgressSdkStep | null;
}

const fontFamily = '"Geist", var(--font-geist-sans), system-ui, sans-serif';
const primary = "var(--foreground-primary, #161615)";
const muted = "var(--foreground-muted, #848483)";
const border = "var(--border-default, #E8E8E7)";
const brand = "var(--foreground-brand, #006BF4)";
const danger = "var(--foreground-negative, #E92C2C)";

const parseDecimal = (value: unknown) => {
  if (value === null || value === undefined || value === "") return undefined;
  if (Decimal.isDecimal(value)) return value;
  const cleaned = String(value).replace(/[^0-9.-]/g, "");
  if (!cleaned || cleaned === "-" || cleaned === "." || cleaned === "-.") {
    return undefined;
  }
  try {
    const parsed = new Decimal(cleaned);
    return parsed.isFinite() ? parsed : undefined;
  } catch {
    return undefined;
  }
};

const formatDecimal = (value: unknown, decimals = 2) =>
  (parseDecimal(value) ?? new Decimal(0)).toDecimalPlaces(decimals).toFixed();

const formatUsd = (value: unknown) => `$${formatDecimal(value, 2)}`;

const unique = (values: Array<string | undefined>) =>
  Array.from(new Set(values.filter(Boolean) as string[]));

const formatSymbolSummary = (symbols: string[]) => {
  if (symbols.length <= 2) return symbols.join(", ");
  return `${symbols.slice(0, 2).join(", ")} and ${symbols.length - 2} others`;
};

const getStepType = (step?: ProgressSdkStep) =>
  String((step as any)?.type ?? (step as any)?.typeID ?? "").toUpperCase();

type ProgressStatusId =
  | "approveTokens"
  | "swapTokens"
  | "receiveToken"
  | "action";

type ProgressStatusState =
  | "default"
  | "preapproval"
  | "inProgress"
  | "completed"
  | "error";

type ProgressStatusRow = {
  id: ProgressStatusId;
  label: string;
  description?: string;
  state: ProgressStatusState;
};

const STATUS_ORDER: ProgressStatusId[] = [
  "approveTokens",
  "swapTokens",
  "receiveToken",
  "action",
];

const SWAP_APPROVAL_TYPES = [
  "CREATE_PERMIT_EOA_TO_EPHEMERAL",
  "CREATE_PERMIT_FOR_SOURCE_SWAP",
];

const REFUND_ELIGIBLE_SWAP_TYPES = ["RFF_ID", "BRIDGE_DEPOSIT"];

const DESTINATION_SWAP_TYPES = [
  "DESTINATION_SWAP_BATCH_TX",
  "DESTINATION_SWAP_HASH",
];

const getStatusForStep = (
  step: ProgressSdkStep | undefined,
  mode: NexusOneMode,
): ProgressStatusId | null => {
  const type = getStepType(step);

  if (
    type === "APPROVAL" ||
    type === "TRANSACTION_SENT" ||
    type === "TRANSACTION_CONFIRMED"
  ) {
    return mode === "swap" ? null : "action";
  }

  if (type.includes("SWAP_START")) {
    return "swapTokens";
  }

  if (SWAP_APPROVAL_TYPES.some((token) => type.includes(token))) {
    return "approveTokens";
  }

  if (
    type.includes("SOURCE_SWAP") ||
    type.includes("SOURCE_BATCH") ||
    type.includes("SWAP_SOURCE") ||
    type.includes("SWAP_COMPLETE") ||
    type.includes("SWAP_SKIPPED")
  ) {
    return "swapTokens";
  }

  if (
    type.includes("DESTINATION_SWAP") ||
    type.includes("DESTINATION_BATCH") ||
    type.includes("BRIDGE_DEPOSIT")
  ) {
    return "receiveToken";
  }

  return null;
};

const stepMatches = (
  step: ProgressSdkStep | undefined,
  tokens: string[],
) => {
  const type = getStepType(step);
  return tokens.some((token) => type.includes(token));
};

const hasCompletedType = (
  events: NexusOneProgressEvent[],
  steps: ProgressStep[],
  tokens: string[],
) => {
  const completedEvent = events.some(
    (event) => event.completed && stepMatches(event.step, tokens),
  );
  if (completedEvent) return true;

  return steps.some(
    (item) => item.completed && stepMatches(item.step, tokens),
  );
};

const hasStepType = (
  events: NexusOneProgressEvent[],
  steps: ProgressStep[],
  tokens: string[],
) =>
  events.some(
    (event) =>
      stepMatches(event.step, tokens) ||
      (event.steps ?? []).some((step) => stepMatches(step, tokens)),
  ) ||
  steps.some((item) => stepMatches(item.step, tokens));

const hasEventType = (
  events: NexusOneProgressEvent[],
  tokens: string[],
) =>
  events.some(
    (event) =>
      stepMatches(event.step, tokens) ||
      (event.steps ?? []).some((step) => stepMatches(step, tokens)),
  );

const getListedSteps = (
  events: NexusOneProgressEvent[],
  eventName: "SWAP_STEPS_LIST" | "STEPS_LIST",
) => {
  const listEvent = [...events]
    .reverse()
    .find((event) => event.name === eventName && (event.steps?.length ?? 0) > 0);
  return listEvent?.steps ?? [];
};

const getEventStepCount = (
  events: NexusOneProgressEvent[],
  eventName: "SWAP_STEP_COMPLETE" | "STEP_COMPLETE",
  tokens: string[],
  completedOnly = false,
) =>
  events.filter((event) => {
    if (event.name !== eventName || !event.step) return false;
    if (completedOnly && !event.completed) return false;
    return stepMatches(event.step, tokens);
  }).length;

const countListedSteps = (
  steps: ProgressSdkStep[],
  tokens: string[],
) => steps.filter((step) => stepMatches(step, tokens)).length;

const getApprovalTotalFromSwapStepsList = (
  events: NexusOneProgressEvent[],
) => countListedSteps(getListedSteps(events, "SWAP_STEPS_LIST"), SWAP_APPROVAL_TYPES);

const hasStartedStatus = (
  events: NexusOneProgressEvent[],
  id: ProgressStatusId,
  mode: NexusOneMode,
) => events.some((event) => getStatusForStep(event.step, mode) === id);

const buildStatusRows = ({
  events,
  failedStep,
  mode,
  steps,
  approvalTotalCount,
  context,
}: {
  events: NexusOneProgressEvent[];
  failedStep?: ProgressSdkStep | null;
  mode: NexusOneMode;
  steps: ProgressStep[];
  approvalTotalCount?: number | null;
  context: {
    destinationChain?: string;
    destinationSymbol?: string;
    opportunityName?: string;
  };
}): ProgressStatusRow[] => {
  const failedStatus = failedStep ? getStatusForStep(failedStep, mode) : null;
  const swapListSteps = getListedSteps(events, "SWAP_STEPS_LIST");
  const fallbackSteps = steps.map((item) => item.step);
  const destinationSymbol = context.destinationSymbol || "token";
  const destinationChain = context.destinationChain || "destination";
  const opportunityName = context.opportunityName || "app";
  const immutableApprovalTotal =
    approvalTotalCount ?? countListedSteps(swapListSteps, SWAP_APPROVAL_TYPES);
  const refundEligibleFailure =
    failedStep !== null &&
    failedStep !== undefined &&
    stepMatches(failedStep, REFUND_ELIGIBLE_SWAP_TYPES);
  const approvalCompletedCount = Math.min(
    immutableApprovalTotal || Number.MAX_SAFE_INTEGER,
    getEventStepCount(
      events,
      "SWAP_STEP_COMPLETE",
      SWAP_APPROVAL_TYPES,
      true,
    ),
  );
  const hasSwapList = swapListSteps.length > 0 || hasStepType(events, steps, [
    "SWAP_START",
    "DETERMINING_SWAP",
    "SOURCE_SWAP",
    "DESTINATION_SWAP",
    "BRIDGE_DEPOSIT",
    "SWAP_COMPLETE",
    "SWAP_SKIPPED",
  ]);
  const hasReceiveTokenStep =
    countListedSteps(swapListSteps, DESTINATION_SWAP_TYPES) > 0 ||
    countListedSteps(fallbackSteps, DESTINATION_SWAP_TYPES) > 0;
  const destinationSwapStarted = hasEventType(events, DESTINATION_SWAP_TYPES);
  const swapComplete = hasCompletedType(events, steps, [
    "SWAP_COMPLETE",
    "SWAP_SKIPPED",
  ]);
  const swapSkipped = hasCompletedType(events, steps, ["SWAP_SKIPPED"]);
  const shouldShowSwapRows =
    hasSwapList && !(swapSkipped && (mode === "deposit" || mode === "send"));
  const swapTokensComplete = hasReceiveTokenStep
    ? destinationSwapStarted
    : swapComplete;
  const receiveTokenComplete = hasReceiveTokenStep && swapComplete;
  const transactionSent = hasCompletedType(events, steps, [
    "TRANSACTION_SENT",
  ]);
  const transactionConfirmed = hasCompletedType(events, steps, [
    "TRANSACTION_CONFIRMED",
  ]);
  const rows: ProgressStatusRow[] = [];

  const pushRow = (row: ProgressStatusRow) => {
    if (failedStatus) {
      const failedIndex = STATUS_ORDER.indexOf(failedStatus);
      const currentIndex = STATUS_ORDER.indexOf(row.id);
      if (failedIndex >= 0 && currentIndex > failedIndex) return;
    }
    rows.push(row);
  };

  if (immutableApprovalTotal > 0) {
    const approvalCurrent = Math.min(
      immutableApprovalTotal,
      Math.max(1, approvalCompletedCount + 1),
    );
    let state: ProgressStatusState = "default";
    if (failedStatus === "approveTokens") {
      state = "error";
    } else if (approvalCompletedCount >= immutableApprovalTotal) {
      state = "completed";
    } else if (
      hasStartedStatus(events, "approveTokens", mode) ||
      events.length === 0
    ) {
      state = "preapproval";
    }

    pushRow({
      id: "approveTokens",
      state,
      description: state === "preapproval" ? "Approve in wallet" : undefined,
      label:
        state === "completed"
          ? `Approved tokens for swap (${immutableApprovalTotal} of ${immutableApprovalTotal})`
          : state === "error"
            ? "Collection failed"
            : `Approve tokens for swap (${approvalCurrent} of ${immutableApprovalTotal})`,
    });
  }

  if (shouldShowSwapRows) {
    const approvalsSatisfied =
      immutableApprovalTotal === 0 ||
      approvalCompletedCount >= immutableApprovalTotal;
    let state: ProgressStatusState = "default";
    if (failedStatus === "swapTokens") {
      state = "error";
    } else if (swapTokensComplete) {
      state = "completed";
    } else if (
      approvalsSatisfied &&
      (hasStartedStatus(events, "swapTokens", mode) ||
        hasEventType(events, [
          "DESTINATION_SWAP_BATCH_TX",
          "BRIDGE_DEPOSIT",
          "SOURCE_SWAP_BATCH_TX",
          "SOURCE_SWAP_HASH",
          "SWAP_START",
        ]))
    ) {
      state = "inProgress";
    }

    pushRow({
      id: "swapTokens",
      state,
      label:
        state === "completed"
          ? "Swaps completed"
          : state === "error"
            ? refundEligibleFailure
              ? "Swap failed. Refund initiated"
              : "Swap failed"
            : state === "inProgress"
              ? "Swaps in progress"
              : "Swap tokens",
    });

    if (hasReceiveTokenStep) {
      pushRow({
        id: "receiveToken",
        state:
          failedStatus === "receiveToken"
            ? "error"
            : receiveTokenComplete
              ? "completed"
              : destinationSwapStarted
                ? "inProgress"
                : "default",
        label:
          failedStatus === "receiveToken"
            ? refundEligibleFailure
              ? "Destination swap failed. Refund initiated."
              : "Destination swap failed."
            : receiveTokenComplete
              ? `Received ${destinationSymbol} on ${destinationChain}`
              : destinationSwapStarted
                ? `Receiving ${destinationSymbol} on ${destinationChain}`
                : `Receive ${destinationSymbol} on ${destinationChain}`,
      });
    }
  }

  if (mode === "deposit" || mode === "send") {
    const receiveComplete =
      swapSkipped ||
      !shouldShowSwapRows ||
      (hasReceiveTokenStep ? receiveTokenComplete : swapTokensComplete);
    const isDeposit = mode === "deposit";
    let state: ProgressStatusState = "default";
    if (failedStatus === "action") {
      state = "error";
    } else if (transactionConfirmed) {
      state = "completed";
    } else if (transactionSent) {
      state = "inProgress";
    } else if (receiveComplete) {
      state = "preapproval";
    }

    pushRow({
      id: "action",
      state,
      description: state === "preapproval" ? "Approve in wallet" : undefined,
      label: isDeposit
        ? state === "completed"
          ? `${destinationSymbol} deposited to ${opportunityName}`
          : state === "inProgress"
            ? `Depositing ${destinationSymbol} to ${opportunityName}`
            : state === "error"
              ? "Deposit failed. Funds are in your wallet."
              : state === "preapproval"
                ? `Approve ${destinationSymbol} deposit to ${opportunityName}`
                : `Deposit ${destinationSymbol} to ${opportunityName}`
        : state === "completed"
          ? `${destinationSymbol} sent`
          : state === "inProgress"
            ? `Sending ${destinationSymbol}`
            : state === "error"
              ? "Send failed. Funds are in your wallet."
              : state === "preapproval"
                ? `Approve ${destinationSymbol} transfer`
                : `Send ${destinationSymbol}`,
    });
  }

  const orderedRows = rows.sort(
    (a, b) => STATUS_ORDER.indexOf(a.id) - STATUS_ORDER.indexOf(b.id),
  );

  if (
    orderedRows.some(
      (row) => row.state === "preapproval" || row.state === "inProgress",
    ) ||
    orderedRows.some((row) => row.state === "error")
  ) {
    return orderedRows;
  }

  const nextActiveIndex = orderedRows.findIndex(
    (row) => row.state === "default",
  );
  if (nextActiveIndex === -1) return orderedRows;

  return orderedRows.map((row, index) => {
    if (index !== nextActiveIndex) return row;
    const nextState =
      row.id === "approveTokens" || row.id === "action"
        ? "preapproval"
        : "inProgress";
    return {
      ...row,
      description: nextState === "preapproval" ? "Approve in wallet" : undefined,
      label:
        row.id === "swapTokens"
          ? "Swaps in progress"
          : row.id === "receiveToken"
            ? `Receiving ${destinationSymbol} on ${destinationChain}`
            : row.label,
      state: nextState,
    };
  });
};

function MiniLogo({
  src,
  label,
  size,
  style,
}: {
  src?: string;
  label?: string;
  size: number;
  style?: React.CSSProperties;
}) {
  const [failed, setFailed] = useState(!src);

  useEffect(() => {
    setFailed(!src);
  }, [src]);

  if (!failed && src) {
    return (
      <img
        src={src}
        alt={label || ""}
        onError={() => setFailed(true)}
        style={{
          background: "#FFFFFE",
          borderRadius: "999px",
          height: size,
          objectFit: "cover",
          width: size,
          ...style,
        }}
      />
    );
  }

  return (
    <span
      style={{
        alignItems: "center",
        background: "#E8F0FF",
        borderRadius: "999px",
        color: brand,
        display: "inline-flex",
        fontFamily,
        fontSize: Math.max(10, Math.round(size * 0.42)),
        fontWeight: 700,
        height: size,
        justifyContent: "center",
        width: size,
        ...style,
      }}
    >
      {(label || "?").trim().slice(0, 1).toUpperCase()}
    </span>
  );
}

function TokenLogoPair({
  tokenLogo,
  chainLogo,
  tokenSymbol,
  chainName,
}: {
  tokenLogo?: string;
  chainLogo?: string;
  tokenSymbol?: string;
  chainName?: string;
}) {
  return (
    <span
      style={{
        display: "inline-flex",
        flexShrink: 0,
        height: 34,
        position: "relative",
        width: 34,
      }}
    >
      <MiniLogo src={tokenLogo} label={tokenSymbol} size={34} />
      {chainLogo && (
        <MiniLogo
          src={chainLogo}
          label={chainName}
          size={14}
          style={{
            bottom: -1,
            outline: "1px solid #FFFFFE",
            position: "absolute",
            right: -1,
          }}
        />
      )}
    </span>
  );
}

export function NexusOneProgressScreen({
  fromTokens = [],
  toToken,
  fromAmountUsd,
  toAmount,
  intentData,
  mode,
  opportunity,
  steps,
  progressEvents = [],
  failedStep,
}: NexusOneProgressScreenProps) {
  const intentSources = intentData?.sources ?? [];
  const intentDestination = intentData?.destination;
  const sourceSymbols =
    intentSources.length > 0
      ? unique(intentSources.map((source) => source.token.symbol))
      : unique(fromTokens.map((token) => token.symbol));
  const sourceUsd =
    intentSources.length > 0
      ? intentSources.reduce(
        (sum, source) => sum.plus(parseDecimal(source.value) ?? 0),
        new Decimal(0),
      )
      : parseDecimal(fromAmountUsd);
  const destinationAmount =
    (mode === "deposit" || mode === "send") && toAmount
      ? toAmount
      : intentDestination?.amount ?? toAmount ?? "0";
  const destinationSymbol =
    intentDestination?.token.symbol || toToken?.symbol || opportunity?.tokenSymbol || "";
  const destinationChainName =
    intentDestination?.chain.name || toToken?.chainName || "";
  const destinationChain =
    mode === "deposit"
      ? opportunity?.title || opportunity?.protocol || destinationChainName
      : destinationChainName;
  const computedApprovalTotal =
    getApprovalTotalFromSwapStepsList(progressEvents);
  const [lockedApprovalTotal, setLockedApprovalTotal] = useState<number | null>(
    null,
  );
  const approvalTotalCount =
    lockedApprovalTotal ?? (computedApprovalTotal > 0 ? computedApprovalTotal : null);

  useEffect(() => {
    if (progressEvents.length === 0) {
      setLockedApprovalTotal(null);
      return;
    }
    if (lockedApprovalTotal !== null || computedApprovalTotal <= 0) return;
    setLockedApprovalTotal(computedApprovalTotal);
  }, [computedApprovalTotal, lockedApprovalTotal, progressEvents.length]);

  const statusRows = buildStatusRows({
    events: progressEvents,
    failedStep,
    mode,
    steps: steps ?? [],
    approvalTotalCount,
    context: {
      destinationChain: destinationChainName || destinationChain,
      destinationSymbol,
      opportunityName: opportunity?.title || opportunity?.protocol,
    },
  });
  const [stepsExpanded, setStepsExpanded] = useState(true);
  const activeRow =
    statusRows.find(
      (row) => row.state === "preapproval" || row.state === "inProgress",
    ) ??
    statusRows.find((row) => row.state === "error") ??
    statusRows.find((row) => row.state === "default") ??
    statusRows[statusRows.length - 1];
  const visibleRows = stepsExpanded ? statusRows : activeRow ? [activeRow] : [];
  const canExpand = statusRows.length > 1;
  const getRowHeight = (row: ProgressStatusRow) =>
    row.description ? 58 : 48;
  const collapsedStatusHeight = activeRow ? getRowHeight(activeRow) : 48;
  const expandedStatusHeight = statusRows.reduce(
    (sum, row) => sum + getRowHeight(row),
    0,
  );

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
      <div
        style={{
          background: "#FFFFFE",
          border: `1px solid ${border}`,
          borderRadius: "12px",
          boxShadow: "0px 1px 12px 0px #5B5B5B0D",
          boxSizing: "border-box",
          padding: "18px 20px 14px",
          width: "100%",
        }}
      >
        <div
          style={{
            color: muted,
            fontFamily,
            fontSize: "12px",
            lineHeight: "16px",
            textAlign: "center",
          }}
        >
          {formatSymbolSummary(sourceSymbols)}
        </div>
        <div
          style={{
            color: primary,
            fontFamily,
            fontSize: "22px",
            fontWeight: 600,
            lineHeight: "28px",
            marginTop: "2px",
            textAlign: "center",
          }}
        >
          {formatUsd(sourceUsd)}
        </div>

        <img
          src="/nexus-one/progress-grid.gif"
          alt=""
          aria-hidden="true"
          style={{
            display: "block",
            height: "148px",
            margin: "18px auto 12px",
            objectFit: "cover",
            width: "100%",
          }}
        />

        <div
          style={{
            alignItems: "center",
            display: "flex",
            flexDirection: "column",
            gap: "4px",
          }}
        >
          <div
            style={{
              alignItems: "center",
              color: primary,
              display: "flex",
              fontFamily,
              fontSize: "20px",
              fontWeight: 600,
              gap: "8px",
              lineHeight: "26px",
            }}
          >
            <TokenLogoPair
              tokenLogo={(intentDestination?.token as any)?.logo || toToken?.logo}
              chainLogo={intentDestination?.chain.logo || toToken?.chainLogo}
              tokenSymbol={destinationSymbol}
              chainName={destinationChain}
            />
            <span>{formatDecimal(destinationAmount, 9)}</span>
            <span style={{ fontSize: "13px", lineHeight: "18px" }}>
              {destinationSymbol}
            </span>
          </div>
          {destinationChain && (
            <div
              style={{
                color: muted,
                fontFamily,
                fontSize: "12px",
                lineHeight: "16px",
              }}
            >
              on {destinationChain}
            </div>
          )}
        </div>
      </div>

      <div
        aria-live="polite"
        style={{
          background: "#FFFFFE",
          border: `1px solid ${border}`,
          borderRadius: "10px",
          boxShadow: "0px 1px 12px 0px #5B5B5B0D",
          boxSizing: "border-box",
          overflow: "hidden",
          transition: "box-shadow 220ms ease, border-color 220ms ease",
          width: "100%",
        }}
      >
        <div
          style={{
            display: "grid",
            gridTemplateRows: "1fr",
            maxHeight: stepsExpanded
              ? `${Math.max(48, expandedStatusHeight)}px`
              : `${collapsedStatusHeight}px`,
            overflow: "hidden",
            transition: "max-height 260ms ease",
          }}
        >
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              minHeight: 0,
            }}
          >
            {visibleRows.map((row, index) => {
              const isCompleted = row.state === "completed";
              const isError = row.state === "error";
              const isDefault = row.state === "default";
              const isLoading =
                row.state === "preapproval" || row.state === "inProgress";
              const hasDescription = Boolean(row.description);
              const rowColor = isDefault ? muted : isError ? danger : primary;

              return (
                <button
                  key={row.id}
                  type="button"
                  onClick={() => {
                    if (canExpand) setStepsExpanded((current) => !current);
                  }}
                  style={{
                    alignItems: hasDescription ? "flex-start" : "center",
                    appearance: "none",
                    background: "transparent",
                    border: "0",
                    borderTop:
                      index > 0 && stepsExpanded ? `1px solid ${border}` : "0",
                    boxSizing: "border-box",
                    color: rowColor,
                    cursor: canExpand ? "pointer" : "default",
                    display: "flex",
                    fontFamily,
                    fontSize: "13px",
                    fontWeight: 400,
                    gap: "10px",
                    minHeight: `${getRowHeight(row)}px`,
                    padding: "12px 16px",
                    textAlign: "left",
                    transition:
                      "color 220ms ease, min-height 220ms ease, opacity 220ms ease",
                    width: "100%",
                  }}
                >
                  {isCompleted || isError ? (
                    <span
                      style={{
                        alignItems: "center",
                        background: isError ? danger : brand,
                        borderRadius: "999px",
                        color: "#FFFFFE",
                        display: "inline-flex",
                        height: "18px",
                        justifyContent: "center",
                        width: "18px",
                      }}
                    >
                      {isError ? (
                        <X style={{ height: 12, width: 12 }} />
                      ) : (
                        <Check style={{ height: 13, width: 13 }} />
                      )}
                    </span>
                  ) : isDefault ? (
                    <span
                      style={{
                        background: "#FFFFFE",
                        border: `2px solid ${border}`,
                        borderRadius: "999px",
                        boxSizing: "border-box",
                        display: "inline-flex",
                        height: "18px",
                        width: "18px",
                      }}
                    />
                  ) : (
                    <Loader2
                      className="animate-spin"
                      style={{ color: brand, height: 18, width: 18 }}
                    />
                  )}
                  <span
                    style={{
                      display: "flex",
                      flexDirection: "column",
                      gap: "3px",
                      lineHeight: "18px",
                      minWidth: 0,
                    }}
                  >
                    <span
                      style={{
                        color: rowColor,
                        fontWeight: isLoading ? 600 : 400,
                      }}
                    >
                      {row.label}
                    </span>
                    {row.description && (
                      <span
                        style={{
                          color: isLoading ? brand : muted,
                          fontSize: "12px",
                          fontStyle: "italic",
                          fontWeight: 400,
                          lineHeight: "16px",
                        }}
                      >
                        {row.description}
                      </span>
                    )}
                  </span>
                  {canExpand && index === 0 && (
                    <ChevronDown
                      style={{
                        color: muted,
                        flexShrink: 0,
                        height: 16,
                        marginLeft: "auto",
                        marginTop: hasDescription ? 2 : 0,
                        transform: stepsExpanded
                          ? "rotate(180deg)"
                          : "rotate(0deg)",
                        transition: "transform 220ms ease",
                        width: 16,
                      }}
                    />
                  )}
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

