          {showAutoBadge ? autoBadge : null}
        </div>
        {shouldShowSourceSummary && (
          <button
            onClick={onOpenSourcePicker}
            style={{
              backgroundColor: "#F4F7FE",
              border: "none",
              borderRadius: "6px",
              color: brand,
              cursor: "pointer",
              fontFamily: uiFont,
              fontSize: "12px",
              fontWeight: 500,
              lineHeight: "16px",
              padding: "7px 10px",
            }}
            type="button"
