export const SWAP_CHAIN_DISPLAY_ORDER_SET = new Set<number>(SWAP_CHAIN_DISPLAY_ORDER);
export const sortChainIdsBySwapDisplayOrder = (chainIds: number[]) =>
  [...chainIds].sort((a, b) => {
