              <input
                value={chainQuery}
                onChange={(e) => setChainQuery(e.target.value)}
                onFocus={() => setIsChainSearchFocused(true)}
                onBlur={() => setIsChainSearchFocused(false)}
                placeholder="Search chains"
                style={{
