            }}
            style={{
              alignItems: "center",
              backgroundColor: "#006BF4",
              border: "none",
              borderRadius: 10,
              color: "#FFFFFE",
              cursor: "pointer",
              display: "flex",
              flexShrink: 0,
              fontFamily: '"Geist", system-ui, sans-serif',
              fontSize: 15,
              fontWeight: 600,
              height: 44,
              justifyContent: "center",
              width: "100%",
            }}
          >
            Done
          </button>
          </div>
        </div>
        );
        return portalRoot ? createPortal(chainModal, portalRoot) : chainModal;
      })()}
    </div>
  );
}

