/** Reusable percentage quick-select buttons row with transition wrapper */
function PercentButtons({
  visible,
  onSelect,
  maxLabel = "MAX",
}: {
  visible: boolean;
  onSelect: (pct: number) => void;
  maxLabel?: string;
}) {
  if (!visible) return null;

  return (
    <div
      style={{
        alignItems: "center",
        boxSizing: "border-box",
        display: "flex",
        gap: "5px",
        height: "24px",
        minHeight: "24px",
        opacity: 1,
        overflow: "hidden",
        pointerEvents: "auto",
        transition: "opacity 0.18s ease-out",
        width: "100%",
      }}
    >
      {[25, 50, 75, 100].map((pct) => {
        const label = pct === 100 ? maxLabel : `${pct}%`;
        return (
          <PercentHoverButton
            key={pct}
            label={label}
            onClick={() => onSelect(pct)}
            tabIndex={0}
          />
        );
      })}
    </div>
  );
}

function UnifiedTokenLogoBadge({
  token,
  size = 24,
}: {
  token: SwapTokenOption;
  size?: number;
}) {
  const [popover, setPopover] = useState<{
    left: number;
    top: number;
    width: number;
    maxHeight: number;
  } | null>(null);
  const triggerRef = useRef<HTMLDivElement | null>(null);
  const sources = token.sourceTokens ?? [];
  const chainCount = new Set(
    sources.map((source) => source.chainId ?? source.chainName).filter(Boolean),
  ).size || sources.length;

  const showPopover = () => {
    const rect = triggerRef.current?.getBoundingClientRect();
    if (!rect || typeof window === "undefined") return;
    const width = 250;
    const maxHeight = 260;
    const viewportPadding = 8;
    const left = Math.min(
      Math.max(viewportPadding, rect.right - width),
      window.innerWidth - width - viewportPadding,
    );
    const belowTop = rect.bottom + 8;
    const top =
      belowTop + maxHeight > window.innerHeight
        ? Math.max(viewportPadding, rect.top - maxHeight - 8)
        : belowTop;
    setPopover({ left, top, width, maxHeight });
  };

  return (
    <div
      ref={triggerRef}
      onMouseEnter={showPopover}
      onMouseLeave={() => setPopover(null)}
      style={{
        boxSizing: "border-box",
        flexShrink: 0,
        height: `${size}px`,
        position: "relative",
        width: `${size}px`,
      }}
    >
      <LogoCircle
        src={token.logo}
        alt={token.symbol}
        label={token.symbol}
        size={size}
        fontSize={Math.max(9, Math.floor(size / 2))}
      />
      {chainCount > 0 && (
        <div
          style={{
            alignItems: "center",
            backgroundColor: "#006BF4",
            border: "1px solid #FFFFFE",
            borderRadius: "999px",
            bottom: -3,
            boxSizing: "border-box",
            color: "#FFFFFE",
            display: "flex",
            fontFamily: '"Geist", system-ui, sans-serif',
            fontSize: "8px",
            fontWeight: 700,
            height: "12px",
            justifyContent: "center",
            lineHeight: "12px",
            minWidth: "12px",
            paddingInline: chainCount > 9 ? "3px" : 0,
            position: "absolute",
            right: -3,
          }}
        >
          {chainCount}
        </div>
      )}
      {popover &&
        sources.length > 0 &&
        typeof document !== "undefined" &&
        createPortal(
          <div
            style={{
              backgroundColor: "#FFFFFE",
              border: "1px solid #E8E8E7",
              borderRadius: "10px",
              boxShadow: "0 10px 28px rgba(22, 22, 21, 0.14)",
              boxSizing: "border-box",
              ...tabularNums,
              left: popover.left,
              maxHeight: popover.maxHeight,
              overflowY: "auto",
              padding: "12px",
              pointerEvents: "none",
              position: "fixed",
              top: popover.top,
              width: popover.width,
              zIndex: 2147483647,
            }}
          >
            <div
              style={{
                alignItems: "center",
                display: "flex",
