            >
              <div
                style={{
                  boxSizing: "border-box",
                  color: "#7C7C7A",
                  fontFamily: '"Geist", system-ui, sans-serif',
                  fontSize: "12px",
                  fontWeight: 500,
                  letterSpacing: "0.08em",
                  lineHeight: "20px",
                  textTransform: "uppercase" as const,
                }}
              >
                Recipient
              </div>
              <div
                style={{
                  alignItems: "center",
                  alignSelf: "stretch",
                  boxSizing: "border-box",
                  display: "flex",
                  gap: "10px",
                  justifyContent: "space-between",
                  width: "100%",
