                <div
                  style={{
                    boxSizing: "border-box",
                    color: recipientColor,
                    fontFamily: '"Geist", system-ui, sans-serif',
                    fontSize: "15px",
                    fontVariantNumeric: "tabular-nums",
                    fontWeight: 500,
                    lineHeight: "17px",
