                  <div
                    style={{
                      boxSizing: "border-box",
                      color: "#006BF4",
                      fontFamily: '"Geist", system-ui, sans-serif',
                      fontSize: "12px",
                      fontWeight: 500,
                      lineHeight: "13px",
