    }

    const parsedAmount = parseFiatNumber(amount);
    const hasEnoughForQuote = Boolean(parsedAmount?.gt(0) && toToken);

    if (!hasEnoughForQuote) {
      clearPendingSwapIntent();
      clearSelectedSources();
