      <div
        style={{
          alignItems: "center",
          boxSizing: "border-box",
          display: "flex",
          flexShrink: 0,
          justifyContent: "space-between",
          paddingLeft: "12px",
          paddingRight: "12px",
          paddingTop: "12px",
          width: "100%",
          position: "relative",
          zIndex: 10,
        }}
